import React, { useState, useEffect } from 'react';
import axios from 'axios'; // Hüseyin: API bağlantıları için
import './App.css';

// Backend URL Tanımı (Gereksinimlere göre Spring Boot adresin)
const API_BASE_URL = "http://localhost:8080/api";

function App() {
  const [page, setPage] = useState('login');
  const [filter, setFilter] = useState('Hepsi');

  // HÜSEYİN: VERİ STATE'LERİ (Backend'den gelecekler)
  const [user, setUser] = useState(null);
  const [programs, setPrograms] = useState([]); // G6
  const [workouts, setWorkouts] = useState([]); // G10
  const [points, setPoints] = useState(0);       // G12
  const [badges, setBadges] = useState([]);     // G14
  const [streak, setStreak] = useState(0);       // G16

  // GEREKSİNİM 2: Kullanıcı Girişi
  const handleLogin = async (e) => {
    e.preventDefault();
    try {
      const response = await axios.post(`${API_BASE_URL}/users/login`, {
        email: e.target.email.value,
        password: e.target.password.value
      });
      setUser(response.data);
      setPage('dashboard');
      loadDashboardData(); // Giriş başarılıysa verileri çek
    } catch (error) {
      alert("Giriş Başarısız! Lütfen bilgilerinizi kontrol edin.");
    }
  };

  // DASHBOARD VERİLERİNİ YÜKLEME (G6, G10, G12, G14)
  const loadDashboardData = async () => {
    try {
      const [progRes, workRes, pointRes, badgeRes] = await Promise.all([
        axios.get(`${API_BASE_URL}/programs`),        // G6
        axios.get(`${API_BASE_URL}/workouts`),        // G10
        axios.get(`${API_BASE_URL}/users/points`),    // G12
        axios.get(`${API_BASE_URL}/badges`)           // G14
      ]);
      setPrograms(progRes.data);
      setWorkouts(workRes.data);
      setPoints(pointRes.data);
      setBadges(badgeRes.data);
    } catch (err) { console.error("Veri çekme hatası", err); }
  };

  // GEREKSİNİM 4: Profil Güncelleme
  const updateProfile = async (newData) => {
    await axios.put(`${API_BASE_URL}/users/profile`, newData);
    alert("Profil Güncellendi!");
  };

  // GEREKSİNİM 8: Program Seçme
  const selectProgram = async (id) => {
    await axios.post(`${API_BASE_URL}/programs/${id}/select`);
    const detail = await axios.get(`${API_BASE_URL}/programs/${id}`);
    alert(`Seçilen Program: ${detail.data.name}`);
  };

  // GEREKSİNİM 16: Seri Bilgisi Güncelleme
  const updateStreak = async () => {
    const res = await axios.put(`${API_BASE_URL}/streak`);
    setStreak(res.data.currentStreak);
  };

  // --- EKRANLAR ---
  if (page === 'login' || page === 'register') {
    return (
      <div className="auth-wrapper">
        <div className="auth-container">
          <h1 className="logo-main">FIT<span>STACK</span></h1>
          <form className="auth-form" onSubmit={handleLogin}>
            <input name="email" type="email" placeholder="E-posta" className="auth-input" required />
            <input name="password" type="password" placeholder="Şifre" className="auth-input" required />
            <button type="submit" className="auth-submit">GİRİŞ YAP (G2)</button>
          </form>
          <button className="auth-switch" onClick={() => setPage('register')}>Kayıt Ol</button>
        </div>
      </div>
    );
  }

  return (
    <div className="app-container">
      <nav className="top-nav">
        <div className="logo-small">FIT<span>STACK</span></div>
        <div className="nav-links">
          <span onClick={() => setPage('dashboard')}>DASHBOARD</span>
          <span onClick={() => setPage('profile')}>PROFİL (G4)</span>
          <span className="logout-link" onClick={() => setPage('login')}>ÇIKIŞ</span>
        </div>
      </nav>

      <main className="content-area">
        {page === 'dashboard' ? (
          <div className="dashboard-grid">
            <div className="header-stats">
              <div className="stat-unit">
                <label>GÜNLÜK SERİ (G16)</label>
                <h2 onClick={updateStreak}>🔥 {streak} GÜN</h2>
              </div>
              <div className="stat-unit">
                <label>TOPLAM PUAN (G12)</label>
                <h2 className="xp-text">{points} XP</h2>
              </div>
              <div className="stat-unit">
                <label>ROZETLER (G14)</label>
                <div className="mini-badges">{badges.map(b => b.icon)}</div>
              </div>
            </div>

            <section className="programs-section">
              <h3>PROGRAM LİSTELEME (G6)</h3>
              <div className="program-row">
                {programs.map(p => (
                  <div className="prog-card" key={p.id}>
                    <h4>{p.name}</h4>
                    <button className="action-btn" onClick={() => selectProgram(p.id)}>SEÇ VE DETAY (G8)</button>
                  </div>
                ))}
              </div>
            </section>

            <section className="recent-activity">
              <h3>GEÇMİŞ ANTRENMANLAR (G10)</h3>
              {workouts.map(w => (
                <div className="activity-item" key={w.id}>
                  <p>{w.name} <span>+{w.xp} XP</span></p>
                </div>
              ))}
            </section>
          </div>
        ) : (
          <div className="profile-container">
            <h2>PROFİLİ GÜNCELLE (G4)</h2>
            <button className="action-btn" onClick={() => updateProfile({name: "Yeni Ad"})}>Bilgileri Kaydet</button>
          </div>
        )}
      </main>
    </div>
  );
}

export default App;
